// 分批应用正文格式：宋体小四、两端对齐、首行缩进 2 字符、固定行距 22 磅
var doc = Application.ActiveDocument;
var paragraphs = doc.Paragraphs;
var batchSize = 500;
var total = paragraphs.Count;
var applied = 0;

// 遍历所有段落，识别并格式化正文
for (var i = 1; i <= total; i++) {
    var para = paragraphs.Item(i);
    var range = para.Range;

    // 跳过空段落
    if (range.Text.trim() === "") continue;

    // 简单判断：不是标题编号开头的视为正文
    var text = range.Text.replace(/\r\n/g, "").trim();
    if (/^[\d]+[\. ]|^第 [\d 一二三四五六七八九十]+章|^图|^表/.test(text)) {
        continue; // 跳过标题、图名、表名
    }

    // 应用正文格式
    try {
        var font = range.Font;
        font.NameFarEast = "宋体";
        font.Size = 12; // 小四

        var paraFormat = para.Format;
        paraFormat.Alignment = 3; // 两端对齐
        paraFormat.FirstLineIndent = 24; // 首行缩进 2 字符（约 24 磅）
        paraFormat.LineSpacingRule = 4; // 固定值
        paraFormat.LineSpacing = 22; // 22 磅

        applied++;
    } catch (e) {
        // 跳过无法格式的段落
    }
}

return { success: true, applied: applied, total: total };
